SELECT 
FROM vso_refund t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.order_id = #{orderId}


    AND t.refund_scene = #{refundScene}


    AND t.refund_status = #{refundStatus}

ORDER BY t.id DESC

